-            // Self-reference - skip, handled by emitDirectRecursiveCall
-            .get_var_ref0, .get_var_ref1, .get_var_ref2, .get_var_ref3 => {},
-
-            else => {
-                try self.print("    /* TODO: {s} */\n", .{info.name});
-            },
-        }
-    }
